// ‚îÄ‚îÄ‚îÄ L3 perception view (ADR-008 D2-B-1) ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
// Returned by `viewGetFocused()` (root-level napi export). Mirrors the
// engine-perception `latest_focus` view's `UiElementRef`, with
// `controlType` pre-stringified via `crate::uia::control_type_name` so
// the shape matches the existing `NativeUiaFocusInfo` consumer in
// `desktop-state.ts` (Codex review v3 P1-3 bit-equal contract).

export interface NativeFocusedElement {
  name: string
  automationId: string | null
  controlType: string
  windowTitle: string
}

export interface NativeViewFocusedPipelineStatus {
  initialized: boolean
  /** `true` when the slot's pipeline has had a failed shutdown
   * (Codex review v9 P2-17). Callers should fall back to UIA. */
  poisoned: boolean
  /** Cumulative `Cmd::PushFocus` count. **Focus-only since S2 D2-C**
   * (Codex PR #108 round 1 P2-B): dirty-rect traffic uses a separate
   * Rust-side counter (`PerceptionWorker::processed_dirty_rect_count`).
   * Do NOT use this as overall pipeline activity gauge ‚Äî it explicitly
   * excludes dirty-rect events to keep focus-pipeline telemetry
   * isolated. */
  processedCount: bigint
}

// ‚îÄ‚îÄ‚îÄ L4 envelope helper (S3 D2-E0 P1, ADR-010) ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
// Returned by `viewGetFocusedWithWallclock()`. Used by the L4 envelope
// wrapper (`src/tools/_envelope.ts::makeEnvelopeAware`) to build
// `as_of.wallclock_ms` from L1 event time (NOT server-side `Date.now()`,
// ADR-010 ¬ß5 + ¬ß4.1 Provenance, PR #110 Round 1 P1-4 ÂèçÊòÝ).

export interface NativeFocusedElementWithWallclock {
  /** Focused element shape; **omitted** by napi-rs (NOT set to `null`)
   * when no live focus / pipeline poisoned (PR #112 Round 1 P2-B,
   * user review): napi-rs serialises `Option::None` for nested struct
   * fields by **omitting the key**, not setting it to `null`. The TS
   * type is `optional + null` (rather than the previous `required +
   * null`) so consumers must check both `=== null` and `=== undefined`,
   * or use `result.focused != null` (covers both omission and a
   * hypothetical future explicit null). Same root cause as PR #108
   * `NativeDirtyRectsResult.latest` and memory
   * `feedback_napi_default_export.md`. */
  focused?: NativeFocusedElement | null
  /** Wallclock_ms of the latest live focus event; **omitted** by napi-rs
   * when no event observed yet (same `Option::None` omission semantic
   * as `focused`). Caller uses `Date.now()` + `confidence: degraded`
   * fallback. */
  latestEventWallclockMs?: bigint | null
  /** True when pipeline slot is poisoned. Caller falls back to UIA path. */
  viewPoisoned: boolean
}

// ‚îÄ‚îÄ‚îÄ L3 perception dirty_rects_aggregate view (S2 D2-C) ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
// Returned by `viewGetDirtyRects(monitorIndex)`. Count-only contract spike
// per `docs/adr-008-d2-c-plan.md` ¬ß2.3 / ¬ß3.7 ‚Äî no rect geometry, just a
// per-`(monitor, frame)` count and the latest frame for the queried monitor.

export interface NativeDirtyRectFrame {
  frameIndex: bigint
  count: bigint
}

export interface NativeDirtyRectsResult {
  /** The `monitor_index` the caller asked for, echoed back so the TS
   * layer can confirm round-trip integrity (CLAUDE.md ¬ß3.2 PR #102 ÊïôË®ì). */
  monitorIndex: number
  liveFrameCount: number
  /** Most recent `(frame_index, count)` for this monitor, if any.
   * **Optional** because napi-rs serialises `Option::None` for nested
   * struct fields by **omitting** the key (not setting it to `null`).
   * User review on PR #108 (2026-05-01) pinned the runtime behaviour.
   * Use optional chaining (`result.latest?.frameIndex`) or
   * `result.latest != null` (covers both `undefined` from omission
   * and a hypothetical future `null`). */
  latest?: NativeDirtyRectFrame
}

export interface NativeFocusAndPointResult {
  focused?: NativeUiaFocusInfo | null
  atPoint?: NativeUiaFocusInfo | null
}

