/**
 * ADR-019 Stage 5 ‚Äî typed declaration for the `DirtyRectSubscription` napi
 * class (`src/duplication/mod.rs`). The class shipped with PR #102 (ADR-007
 * P5c-2) and was originally reachable only through an untyped escape hatch
 * (`addon["DirtyRectSubscription"]` in `src/engine/vision-gpu/dirty-rect-source.ts`,
 * removed in ADR-020 SR-4 PR-SR4-3). Both consumers (Stage 5 via
 * `src/engine/any-change.ts`, vision-gpu via `dirty-rect-source.ts`) now go
 * through the shared `DirtyRectBroker` (`src/engine/dxgi-broker.ts`), which
 * is the single typed caller of `nativeDuplication.DirtyRectSubscription`.
 *
 * `outputBounds` is the per-output desktop rect (now populated from
 * `DXGI_OUTPUT_DESC.DesktopCoordinates` after PR #322, so dirty rects are
 * translated to desktop screen coords for ALL monitors, not just primary).
 */
export interface NativeDirtyRectSubscription {
  readonly isDisposed: boolean
  readonly outputBounds: NativeOutputBounds
  next(timeoutMs: number): Promise<NativeDirtyRect[]>
  dispose(): void
}

/**
 * ADR-020 SR-4 PR-SR4-1 ‚Äî re-export of the broker handle interface so
 * downstream consumers (Stage 5 in PR-SR4-2, vision-gpu in PR-SR4-3) can
 * reference the typed handle from a single SSOT (`native-types.ts`).
 *
 * The actual interface definition lives in `src/engine/dxgi-broker.ts`
 * (where the broker class also lives). This file re-exports the type so
 * sub-plan ¬ß5.2's "BrokerSubscription re-exported interface" SSOT row
 * is satisfied without duplicating the declaration.
 *
 * Per Round 2 P1-3 lock: this interface has no `subscribe()` method ‚Äî
 * fan-out is exclusively a `DirtyRectBroker.subscribe()` upper-level API
 * responsibility.
 */
export type { BrokerSubscription } from "./dxgi-broker.js"

